#pragma once

#include <memory>
#include <string>
#include <vector>
#include <opencv2/opencv.hpp>

namespace ai_deployment {

struct InferenceConfig {
    std::string model_path;
    std::string engine_type;  // "tensorrt", "onnx", "ncnn"
    int input_width = 224;
    int input_height = 224;
    float confidence_threshold = 0.5f;
    bool use_gpu = true;
};

class InferenceEngine {
public:
    virtual ~InferenceEngine() = default;
    virtual bool Initialize(const InferenceConfig& config) = 0;
    virtual std::vector<float> Predict(const cv::Mat& image) = 0;
    virtual void Warmup() = 0;
};

class EngineFactory {
public:
    static std::unique_ptr<InferenceEngine> CreateEngine(const std::string& type);
};

} // namespace ai_deployment

